import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import CodeBackground from './components/CodeBackground';
import HackathonCard from './components/HackathonCard';
import { HACKATHON_CLUBS } from './constants';
import { View, User } from './types';

const App: React.FC = () => {
  const [currentView, setView] = useState<View>('home');
  const [user, setUser] = useState<User>({ isLoggedIn: false });

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setUser({ isLoggedIn: true, username: 'Innovator_99' });
    setView('home');
  };

  const handleLogout = () => {
    setUser({ isLoggedIn: false });
    setView('home');
  };

  const renderContent = () => {
    switch (currentView) {
      case 'settings':
        return (
          <div className="max-w-4xl mx-auto py-12 px-6">
            <h1 className="text-4xl font-bold mb-8">Settings</h1>
            <div className="glass p-8 rounded-2xl space-y-6">
              <div>
                <h3 className="text-lg font-semibold mb-2">Profile Visibility</h3>
                <p className="text-slate-400 text-sm mb-4">Control who can see your hackathon participation history.</p>
                <div className="flex items-center gap-4">
                  <button className="px-4 py-2 bg-blue-600 rounded-lg text-sm font-medium">Public</button>
                  <button className="px-4 py-2 bg-slate-800 rounded-lg text-sm font-medium border border-slate-700">Private</button>
                </div>
              </div>
              <div className="h-px bg-slate-800"></div>
              <div>
                <h3 className="text-lg font-semibold mb-2">Notification Preferences</h3>
                <label className="flex items-center gap-3 text-slate-300">
                  <input type="checkbox" className="w-4 h-4 rounded bg-slate-800 border-slate-700" defaultChecked />
                  Email me about new mega hackathons
                </label>
              </div>
            </div>
          </div>
        );
      case 'login':
        return (
          <div className="flex items-center justify-center min-h-[80vh]">
            <div className="glass p-10 rounded-2xl w-full max-w-md">
              <h1 className="text-3xl font-bold mb-2 text-center">Welcome Back</h1>
              <p className="text-slate-400 text-center mb-8">Join the elite network of developers.</p>
              <form onSubmit={handleLogin} className="space-y-6">
                <div>
                  <label className="block text-sm font-medium text-slate-400 mb-1">Username</label>
                  <input 
                    type="text" 
                    placeholder="e.g. hack_master"
                    className="w-full bg-slate-900 border border-slate-800 rounded-lg px-4 py-3 focus:outline-none focus:border-blue-500 transition-colors"
                    required
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-400 mb-1">Password</label>
                  <input 
                    type="password" 
                    placeholder="••••••••"
                    className="w-full bg-slate-900 border border-slate-800 rounded-lg px-4 py-3 focus:outline-none focus:border-blue-500 transition-colors"
                    required
                  />
                </div>
                <button 
                  type="submit"
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg shadow-lg shadow-blue-500/20 transition-all active:scale-95"
                >
                  Sign In
                </button>
              </form>
            </div>
          </div>
        );
      default:
        return (
          <div className="max-w-7xl mx-auto py-12 px-6 lg:px-12">
            <header className="mb-12 relative">
              <div className="absolute -top-10 -left-10 w-40 h-40 bg-blue-600 opacity-10 blur-[100px] pointer-events-none"></div>
              <h1 className="text-5xl lg:text-7xl font-black tracking-tighter mb-4">
                HACKATHONS <span className="text-blue-500">CLUB</span>
              </h1>
              <p className="text-slate-400 text-lg lg:text-xl max-w-2xl leading-relaxed">
                Connect with passionate developers, build disruptive technology, and master your craft in our specialized hackathon tracks.
              </p>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
              {HACKATHON_CLUBS.map(club => (
                <HackathonCard key={club.id} club={club} />
              ))}
            </div>

            <footer className="mt-20 pt-10 border-t border-slate-800 text-center text-slate-500 text-sm">
              <p>&copy; 2024 HackHub International. All rights reserved.</p>
              <div className="flex justify-center gap-6 mt-4">
                <a href="#" className="hover:text-blue-400 transition-colors">Privacy</a>
                <a href="#" className="hover:text-blue-400 transition-colors">Terms</a>
                <a href="#" className="hover:text-blue-400 transition-colors">Discord</a>
              </div>
            </footer>
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen flex bg-slate-950 text-slate-50 selection:bg-blue-500/30">
      <CodeBackground />

      <Sidebar 
        currentView={currentView} 
        setView={setView} 
        user={user}
        onLogout={handleLogout}
      />

      <main className="flex-1 overflow-y-auto z-10">
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

